                /// <summary>
                /// Resolve a method binding.
                /// </summary>
                Method = 1,

                /// <summary>
                /// Resolve a field binding.
                /// </summary>
                Field = 2,

                /// <summary>
                /// Resolve a property binding.
                /// </summary>
                Property = 3
            }

