                    OwnerAlias = ownerAlias;
                    MemberName = memberName;
                }

                /// <summary>
                /// Gets the alias of the declared owner type.
                /// </summary>
                public string OwnerAlias { get; }

                /// <summary>
                /// Gets the runtime member name to resolve.
                /// </summary>
                public string MemberName { get; }

                /// <summary>
