                /// </summary>
                public string? MethodAlias { get; set; }

                /// <summary>
                /// Gets or sets whether the target method is static. Method resolution does not require this, but generated invocation helpers use it.
                /// </summary>
                public bool IsStatic { get; set; }

                /// <summary>
